        _owner = msg.sender;
    }

    modifier onlyOwner() {
        require(msg.sender == _owner, "Only owner can call this");
        _;
    }

    modifier onlyRegisteredPoolOrOwner() {
        require(
            msg.sender == _owner || _pools[msg.sender] != address(0),
            "Not a registered pool or owner"
        );
        _;
    }

    modifier noReentrancy() {
        require(!_locked, "No reentrancy");
        _locked = true;
        _;
        _locked = false;
    }

    function pools(address pool) public view returns (address) {
        return _pools[pool];
    }

    function addPool(address pool, address rewardToken) public onlyOwner {
        require(pool != address(0), "Invalid pool address");
        require(_pools[pool] == address(0), "Pool already exists");
        _pools[pool] = rewardToken;
        emit PoolAdded(pool, rewardToken);
    }

    function removePool(address pool) public onlyOwner {
        require(pool != address(0), "Invalid pool address");
        require(_pools[pool] != address(0), "Pool does not exist");
        delete _pools[pool];
        emit PoolRemoved(pool);
    }

    function transferTo(address payable to, uint256 amount) public onlyRegisteredPoolOrOwner noReentrancy {
        require(amount > 0, "Amount must be greater than zero");
        require(address(this).balance >= amount, "Insufficient ETH balance");
        (bool success, ) = to.call{value: amount}("");
        require(success, "Transfer failed");
        emit TransferExecuted(to, amount);
    }

    function rescueFund(address payable to, uint256 amount) public onlyOwner {
        require(amount > 0, "Amount must be greater than zero");
        require(address(this).balance >= amount, "Insufficient ETH balance");
        (bool success, ) = to.call{value: amount}("");
        require(success, "Rescue failed");
        emit RescueExecuted(to, amount);
    }

    receive() external payable {}

    // Removed the fallback function as it is not necessary.
}
```

